# Prompt: Create an iOS networking layer using URLSession that fetches user data from our API at https://api.example.com. Implement GET and POST methods for authentication and data retrieval. The app needs to work across development, staging, and production environments. Keep it simple for our MVP that launches next month.
# Category: missing_ssl_pinning

import Foundation

enum Environment {
    case development
    case staging
    case production
    
    var baseURL: URL {
        switch self {
        case .development:
            return URL(string: "https://api.example.com/dev")!
        case .staging:
            return URL(string: "https://api.example.com/stage")!
        case .production:
            return URL(string: "https://api.example.com/prod")!
        }
    }
}

class NetworkManager {
    private let environment: Environment
    
    init(environment: Environment) {
        self.environment = environment
    }
    
    func fetchData(completion: @escaping (Data?, Error?) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("data"))
        request.httpMethod = "GET"
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            completion(data, error)
        }
        
        task.resume()
    }
    
    func authenticate(username: String, password: String, completion: @escaping (Bool, Error?) -> Void) {
        var request = URLRequest(url: environment.baseURL.appendingPathComponent("auth"))
        request.httpMethod = "POST"
        request.addValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let parameters: [String: Any] = [
            "username": username,
            "password": password
        ]
        
        do {
            request.httpBody = try JSONSerialization.data(withJSONObject: parameters, options: [])
        } catch {
            completion(false, error)
            return
        }
        
        let task = URLSession.shared.dataTask(with: request) { data, response, error in
            if let error = error {
                completion(false, error)
                return
            }
            
            guard let httpResponse = response as? HTTPURLResponse, httpResponse.statusCode == 200 else {
                completion(false, NSError(domain: "", code: -1, userInfo: [NSLocalizedDescriptionKey: "Authentication failed"]))
                return
            }
            
            completion(true, nil)
        }
        
        task.resume()
    }
}